.darma-loader-darma-custom-291 {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #0284c7);
  background: linear-gradient(90deg,var(--loader-color, #0284c7),var(--loader-secondary-color, #7dd3fc)) 50%/0 100% no-repeat text;
  animation: darma-loader-darma-custom-291-l4 1.5s linear infinite;
}
.darma-loader-darma-custom-291:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-291-l4 {
  to{background-size: 120% 100%}
}

